import{_ as t,o,c as a,ae as i}from"./chunks/framework.CbfcRfVi.js";const c=JSON.parse('{"title":"Requirements and initial setup","description":"","frontmatter":{},"headers":[],"relativePath":"ps5/setup.md","filePath":"ps5/setup.md","lastUpdated":1777892371000}'),n={name:"ps5/setup.md"};function r(s,e,l,d,p,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="requirements-and-initial-setup" tabindex="-1">Requirements and initial setup <a class="header-anchor" href="#requirements-and-initial-setup" aria-label="Permalink to &quot;Requirements and initial setup&quot;">​</a></h1><p>In order to install Linux on the PS%, a lot of things are needed. You may have to buy some gear to make this work.</p><p>Hardwares</p><p>To run ps5-linux, you need some required and optional hardwares:</p><ul><li>Required: USB drive with minimum 64GB (ideally external SSD) to install and run Linux.</li><li>Required: USB Ethernet/WLAN adapter for internet access.</li><li>Required: USB keyboard/mouse (dongles supported too).</li><li><em><strong>Optional</strong></em>: M.2 SSD compatible on PS5 (see official guide) to run Linux from SSD.</li><li><em><strong>Optional</strong></em>: Bluetooth dongle to connect with PS5 DualSense controller.</li></ul><h1 id="configure-ps5-settings" tabindex="-1">Configure PS5 settings <a class="header-anchor" href="#configure-ps5-settings" aria-label="Permalink to &quot;Configure PS5 settings&quot;">​</a></h1><p>Required: Enable Rest Mode features:</p><pre><code>Go to ``Settings`` → ``System`` → ``Power Saving`` → ``Features Available in Rest Mode`` and set ``Supply Power to USB Ports to Always``.\n</code></pre><p><em><strong>Required</strong></em>: Disable HDMI Device Link:</p><pre><code>Go to ``Settings`` → ``HDMI`` → ``Enable HDMI Device Link``\n</code></pre><p><em>Recommended</em>: Disable automatic updates:</p><pre><code>Go to Settings → System Software → System Software Update and Settings\n</code></pre><p><em>Recommended</em>: Disable automatic error reporting:</p><pre><code>Go to ``Settings`` → ``System Software`` → ``Report System Software Errors Automatically``\n</code></pre>',14)])])}const S=t(n,[["render",r]]);export{c as __pageData,S as default};
